  const [error, setError] = useState<string | null>(null);
  const [currentView, setCurrentView] = useState<'home' | 'modules' | 'detail' | 'about'>('home');
  const [selectedModule, setSelectedModule] = useState<Module | null>(null);
  const [searchQuery, setSearchQuery] = useState('');
  const [filterType, setFilterType] = useState<ResourceType | 'All'>('All');
  const [downloadingId, setDownloadingId] = useState<string | null>(null);
  const [aiSuggestions, setAiSuggestions] = useState<string[]>([]);
  const [isDark, setIsDark] = useState(() => localStorage.getItem('gaka-theme') === 'dark');

  // Theme Sync
  useEffect(() => {
    document.documentElement.classList.toggle('dark', isDark);
    localStorage.setItem('gaka-theme', isDark ? 'dark' : 'light');
  }, [isDark]);

  // Data Fetching from Supabase
  const syncData = useCallback(async () => {
    try {
      // 1. Fetch Modules
      const { data: modulesData, error: modulesError } = await supabase
        .from('modules')
        .select('*');

      if (modulesError) throw modulesError;

      // 2. Fetch Resources joined with Module info
      const { data: resourcesData, error: resourcesError } = await supabase
        .from('resources')
        .select('*, modules(code, id)');

      if (resourcesError) throw resourcesError;

      // Map resources to modules
      const finalModules: Module[] = (modulesData || []).map(m => ({
        ...m,
        resources: (resourcesData || [])
          .filter(r => r.module_id === m.id)
          .map(r => ({
            id: r.id.toString(),
            title: r.title,
            type: r.type,
            downloadUrl: transformToDirectDownload(r.url),
            viewUrl: ensureViewUrl(r.url)
          }))
      }));

      // Find 3 most recent resources
      const recent = (resourcesData || [])
        .sort((a, b) => new Date(b.created_at).getTime() - new Date(a.created_at).getTime())
        .slice(0, 3)
        .map(r => ({
          id: r.id.toString(),
          title: r.title,
          type: r.type,
          downloadUrl: transformToDirectDownload(r.url),
          viewUrl: ensureViewUrl(r.url),
          moduleCode: r.modules.code,
          moduleId: r.modules.id
        }));

      setModules(finalModules);
      setRecentFiles(recent);
      localStorage.setItem(CACHE_KEY, JSON.stringify({ modules: finalModules, recent, time: Date.now() }));
      setError(null);
    } catch (err: any) {
      setError(err.message || "Could not sync with Supabase.");
      // Load from cache on failure
      const cached = localStorage.getItem(CACHE_KEY);
      if (cached) {
        const data = JSON.parse(cached);
        setModules(data.modules);
        setRecentFiles(data.recent);
      }
