        const resp = await ai.models.generateContent({
          model: 'gemini-3-flash-preview',
          contents: `Available modules: ${modules.map(m => m.name).join(', ')}. Query: "${searchQuery}". Suggest 2 most likely module names. Return only comma-separated strings.`,
        });
        setAiSuggestions(resp.text?.split(',').map(s => s.trim()) || []);
      } catch (e) { console.error(e); }
    }, 800);
    return () => clearTimeout(timer);
  }, [searchQuery, modules]);

