export default App;

@tailwind base;
@tailwind components;
@tailwind utilities;

:root {
  --brand-primary: #059669;
  --brand-secondary: #0d9488;
}

body {
  font-family: 'Lexend', sans-serif;
  background-color: #fcfdfe;
  color: #1e293b;
  overflow-x: hidden;
  transition: background-color 0.5s cubic-bezier(0.4, 0, 0.2, 1), color 0.5s ease;
}

body.dark {
  background-color: #000000;
  color: rgba(255, 255, 255, 0.87);
}

.glass {
  background: rgba(255, 255, 255, 0.75);
  backdrop-filter: blur(16px);
  -webkit-backdrop-filter: blur(16px);
  border-bottom: 1px solid rgba(241, 245, 249, 0.8);
  transition: background 0.5s ease, border-color 0.5s ease;
}

.dark .glass {
  background: rgba(0, 0, 0, 0.8);
  border-bottom: 1px solid rgba(255, 255, 255, 0.05);
}

.gradient-text {
  background: linear-gradient(135deg, #059669 0%, #10b981 50%, #0d9488 100%);
  -webkit-background-clip: text;
  -webkit-text-fill-color: transparent;
}

.dark .gradient-text {
  background: linear-gradient(135deg, #34d399 0%, #10b981 100%);
  -webkit-background-clip: text;
  -webkit-text-fill-color: transparent;
}

.hero-gradient {
  background: radial-gradient(circle at top right, rgba(16, 185, 129, 0.05), transparent),
              radial-gradient(circle at bottom left, rgba(13, 148, 136, 0.05), transparent);
  transition: background 0.5s ease;
}

.dark .hero-gradient {
  background: radial-gradient(circle at top right, rgba(16, 185, 129, 0.1), transparent),
              radial-gradient(circle at bottom left, rgba(13, 148, 136, 0.06), transparent);
}

@keyframes fadeIn {
  from { opacity: 0; transform: translateY(10px); }
  to { opacity: 1; transform: translateY(0); }
}

.animate-fade-in {
  animation: fadeIn 0.6s cubic-bezier(0.16, 1, 0.3, 1) forwards;
}

.scrollbar-hide::-webkit-scrollbar {
  display: none;
}

.scrollbar-hide {
  -ms-overflow-style: none;
  scrollbar-width: none;
}

h1, h2, h3, h4 {
  letter-spacing: -0.02em;
}

.lamp-glow {
  filter: drop-shadow(0 0 20px rgba(251, 191, 36, 0.9));
}

/* Book Opening Animation */
.book-loader {
  width: 60px;
  height: 45px;
  position: relative;
  perspective: 150px;
}

.book-page {
  width: 30px;
  height: 45px;
  background-color: #059669;
  position: absolute;
  top: 0;
  right: 0;
  transform-origin: left center;
  border-radius: 0 4px 4px 0;
  animation: pageFlip 1.5s infinite ease-in-out;
}

.book-page:nth-child(1) { animation-delay: 0s; z-index: 3; }
.book-page:nth-child(2) { animation-delay: 0.15s; z-index: 2; }
