}

/* Book Opening Animation */
.book-loader {
  width: 60px;
  height: 45px;
  position: relative;
  perspective: 150px;
}

.book-page {
  width: 30px;
  height: 45px;
  background-color: #059669;
  position: absolute;
  top: 0;
  right: 0;
  transform-origin: left center;
  border-radius: 0 4px 4px 0;
  animation: pageFlip 1.5s infinite ease-in-out;
}

.book-page:nth-child(1) { animation-delay: 0s; z-index: 3; }
.book-page:nth-child(2) { animation-delay: 0.15s; z-index: 2; }
.book-page:nth-child(3) { animation-delay: 0.3s; z-index: 1; }

.book-back {
  width: 30px;
  height: 45px;
  background-color: #047857;
  position: absolute;
  top: 0;
  left: 0;
  border-radius: 4px 0 0 4px;
}

@keyframes pageFlip {
  0% { transform: rotateY(0deg); }
  50% { transform: rotateY(-180deg); }
  100% { transform: rotateY(-180deg); }
}

