    const { data, error } = await supabase
      .from('portal_users')
      .select('*')
      .eq('id', userId)
      .single();

    if (data) {
      setProfile(data as Profile);
    } else {
      localStorage.removeItem('gaka-session-id');
      setProfile(null);
    }
  };

