    // Direct table query for "Simple Auth"
    const { data, error } = await supabase
      .from('portal_users')
      .select('*')
      .eq('username', username)
      .eq('password', pass)
      .single();

    if (error || !data) {
      throw new Error("Invalid username or password.");
    }

    setProfile(data as Profile);
    localStorage.setItem('gaka-session-id', data.id);
    setCurrentView('home');
  };

