      .from('portal_users')
      .insert([
        { username, password: pass, full_name: name, email, role: 'student' }
      ])
      .select()
      .single();

    if (error) throw error;

    setProfile(data as Profile);
    localStorage.setItem('gaka-session-id', data.id);
