                    <h4 className="text-[10px] font-black uppercase tracking-widest text-slate-400 dark:text-white/20 mb-4">Dev Team</h4>
                    <p className="text-slate-900 dark:text-white font-black text-2xl mb-2">Softlink Africa</p>
