                    <p className="text-slate-400 dark:text-white/20 font-black italic uppercase tracking-[0.3em] text-xl">Empty directory.</p>
                  </div>
                )}
              </div>
            </div>
          </div>
        )}

        {currentView === 'about' && (
          <div className="animate-fade-in max-w-5xl mx-auto py-10 sm:py-24">
