import React, { useState, useEffect, useMemo } from 'react';
import { createClient } from '@supabase/supabase-js';
import { Navbar } from './components/Navbar';
import { ModuleCard } from './components/ModuleCard';
import { AuthPage } from './components/AuthPage';
import { SearchIcon, BackIcon, FileIcon, DownloadIcon, ShareIcon, ChevronRightIcon, ViewIcon, PlusIcon, EditIcon, TrashIcon, BookmarkIcon, BookmarkFilledIcon } from './components/Icons';
import { Module, ResourceType, AcademicFile, Profile } from './types';
import { Analytics } from '@vercel/analytics/react';

// --- SUPABASE CONFIGURATION ---
const SUPABASE_URL = "https://tgnljtmvigschazflxis.supabase.co";
const SUPABASE_ANON_KEY = "sb_publishable_nXfVOz8QEqs1mT0sxx_nYw_P8fmPVmI";
const supabase = createClient(SUPABASE_URL, SUPABASE_ANON_KEY);

type ViewState = 'home' | 'modules' | 'detail' | 'about' | 'auth' | 'saved';

const App: React.FC = () => {
  const [modules, setModules] = useState<Module[]>([]);
  const [recentFiles, setRecentFiles] = useState<(AcademicFile & { moduleCode: string; moduleId: string })[]>([]);
  const [isLoading, setIsLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);
  const [currentView, setCurrentView] = useState<ViewState>('home');
  const [selectedModule, setSelectedModule] = useState<Module | null>(null);
  const [searchQuery, setSearchQuery] = useState('');
  const [filterType, setFilterType] = useState<ResourceType | 'All'>('All');
  const [downloadingId, setDownloadingId] = useState<string | null>(null);
  const [isProcessing, setIsProcessing] = useState(false);

  // User Saved Resources State
  const [savedResourceIds, setSavedResourceIds] = useState<string[]>(() => {
    const saved = localStorage.getItem('gaka-saved-resources');
    return saved ? JSON.parse(saved) : [];
  });

  const [isResourceModalOpen, setIsResourceModalOpen] = useState(false);
  const [editingResource, setEditingResource] = useState<AcademicFile | null>(null);
  const [resourceFormData, setResourceFormData] = useState({
    title: '',
    type: 'Notes' as ResourceType,
    viewUrl: '',
    downloadUrl: ''
  });

  const [profile, setProfile] = useState<Profile | null>(null);
  const [isDark, setIsDark] = useState(() => {
    const saved = localStorage.getItem('gaka-theme');
    if (saved) return saved === 'dark';
    return window.matchMedia('(prefers-color-scheme: dark)').matches;
  });

  // Sync theme
  useEffect(() => {
    localStorage.setItem('gaka-theme', isDark ? 'dark' : 'light');
    if (isDark) document.documentElement.classList.add('dark');
    else document.documentElement.classList.remove('dark');
  }, [isDark]);

  // Sync saved resources
  useEffect(() => {
    localStorage.setItem('gaka-saved-resources', JSON.stringify(savedResourceIds));
  }, [savedResourceIds]);

  useEffect(() => {
    const savedUserId = localStorage.getItem('gaka-session-id');
    if (savedUserId) fetchProfile(savedUserId);
    fetchData();
  }, []);

  const fetchProfile = async (userId: string) => {
    const { data } = await supabase.from('portal_users').select('*').eq('id', userId).single();
    if (data) setProfile(data as Profile);
    else {
      localStorage.removeItem('gaka-session-id');
      setProfile(null);
    }
  };

  const fetchData = async () => {
    try {
      setIsLoading(true);
      const { data: mData } = await supabase.from('modules').select('*').order('code');
      const { data: rData } = await supabase.from('resources').select('*, modules(code)').order('created_at', { ascending: false });

      const finalModules: Module[] = (mData || []).map(m => ({
        id: m.id,
        code: m.code,
        name: m.name,
        description: m.description || 'Verified academic resource module.',
        resources: (rData || [])
          .filter(r => r.module_id === m.id)
          .map(r => ({
            id: r.id,
            title: r.title,
            type: r.type as ResourceType,
            downloadUrl: r.download_url || '#',
            viewUrl: r.view_url || '#',
          }))
      }));

      setModules(finalModules);

      const topRecent = (rData || []).slice(0, 3).map(r => ({
        id: r.id,
        title: r.title,
        type: r.type as ResourceType,
        downloadUrl: r.download_url,
        viewUrl: r.view_url,
        moduleCode: r.modules?.code || 'CS',
        moduleId: r.module_id
      }));
      setRecentFiles(topRecent);
    } catch (err) {
      setError("Sync failure.");
    } finally {
      setIsLoading(false);
    }
  };

  const handleLogin = async (u: string, p: string) => {
    const { data, error } = await supabase.from('portal_users').select('*').eq('username', u).eq('password', p).single();
    if (error || !data) throw new Error("Invalid access keys.");
    setProfile(data as Profile);
    localStorage.setItem('gaka-session-id', data.id);
    setCurrentView('modules');
  };

  const handleSignup = async (u: string, p: string, n: string, e: string) => {
    const { data: existing } = await supabase.from('portal_users').select('username').eq('username', u).maybeSingle();
    if (existing) throw new Error("Username taken.");
    const { data, error } = await supabase.from('portal_users').insert([{ username: u, password: p, full_name: n, email: e, role: 'student' }]).select().single();
    if (error) throw error;
    setProfile(data as Profile);
    localStorage.setItem('gaka-session-id', data.id);
    setCurrentView('modules');
  };

  const handleLogout = () => {
    localStorage.removeItem('gaka-session-id');
    setProfile(null);
    setCurrentView('home');
  };

  const handleSaveResource = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!selectedModule) return;
    setIsProcessing(true);
    try {
      const payload = {
        title: resourceFormData.title,
        type: resourceFormData.type,
        view_url: resourceFormData.viewUrl,
        download_url: resourceFormData.downloadUrl,
        module_id: selectedModule.id
      };
      if (editingResource) await supabase.from('resources').update(payload).eq('id', editingResource.id);
      else await supabase.from('resources').insert([payload]);
      setIsResourceModalOpen(false);
      await fetchData();
    } catch (err: any) {
      alert(err.message);
    } finally {
      setIsProcessing(false);
    }
  };

  const handleDeleteResource = async (id: string) => {
    if (!confirm("Remove permanently?")) return;
    await supabase.from('resources').delete().eq('id', id);
    await fetchData();
  };

  const openAddModal = () => {
    setEditingResource(null);
    setResourceFormData({ title: '', type: 'Notes', viewUrl: '', downloadUrl: '' });
    setIsResourceModalOpen(true);
  };

  const openEditModal = (r: AcademicFile) => {
    setEditingResource(r);
    setResourceFormData({ title: r.title, type: r.type, viewUrl: r.viewUrl, downloadUrl: r.downloadUrl });
    setIsResourceModalOpen(true);
  };

  const toggleSave = (id: string) => {
    setSavedResourceIds(prev => prev.includes(id) ? prev.filter(rid => rid !== id) : [...prev, id]);
  };

  const navigateTo = (view: ViewState, module?: Module) => {
    if (module) setSelectedModule(module);
    setCurrentView(view);
    window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  const filteredModules = useMemo(() => {
    const q = searchQuery.toLowerCase();
    return modules.filter(m => m.name.toLowerCase().includes(q) || m.code.toLowerCase().includes(q));
  }, [modules, searchQuery]);

  const filteredResources = useMemo(() => {
    if (!selectedModule) return [];
    return selectedModule.resources.filter(r => filterType === 'All' || r.type === filterType);
  }, [selectedModule, filterType]);

  const savedResources = useMemo(() => {
    const all = modules.flatMap(m => m.resources.map(r => ({ ...r, moduleCode: m.code })));
    return all.filter(r => savedResourceIds.includes(r.id));
  }, [modules, savedResourceIds]);

  const handleShare = (title: string) => {
    window.open(`https://wa.me/?text=${encodeURIComponent(`Academic Resource: *${title}*\n${window.location.origin}`)}`, '_blank');
  };

  const ResourceItem: React.FC<{ file: AcademicFile; moduleCode?: string; delay: number }> = ({ file, moduleCode, delay }) => {
    const isSaved = savedResourceIds.includes(file.id);
    const [isDownloading, setIsDownloading] = useState(false);

    const onDownload = (e: React.MouseEvent) => {
      if (file.downloadUrl === '#') e.preventDefault();
      else {
        setIsDownloading(true);
        setTimeout(() => setIsDownloading(false), 3000);
      }
    };

    return (
      <div 
        className="group flex flex-col sm:flex-row sm:items-center justify-between p-5 sm:p-8 bg-white dark:bg-[#1A1A1A] hover:bg-slate-50 dark:hover:bg-[#222] border border-slate-100 dark:border-white/5 rounded-[2.5rem] transition-all duration-500 animate-fade-in"
        style={{ animationDelay: `${delay}ms` }}
      >
        <div className="flex items-center space-x-5 sm:space-x-7 mb-6 sm:mb-0">
          <div className={`w-12 h-12 sm:w-16 sm:h-16 rounded-2xl sm:rounded-3xl flex items-center justify-center flex-shrink-0 transition-all duration-500 group-hover:scale-105 shadow-sm ${
            file.type === 'Notes' ? 'bg-emerald-50 dark:bg-emerald-500/10 text-emerald-600 dark:text-emerald-400' : 'bg-teal-50 dark:bg-teal-500/10 text-teal-600 dark:text-teal-400'
          }`}>
            <FileIcon className="w-6 h-6 sm:w-8 sm:h-8" />
          </div>
          <div className="min-w-0">
            <div className="flex items-center space-x-2.5 mb-1">
              {moduleCode && (
                <span className="text-[9px] sm:text-[10px] font-black bg-slate-100 dark:bg-black text-slate-500 dark:text-white/40 px-2 py-0.5 rounded-md uppercase border dark:border-white/5">
                  {moduleCode}
                </span>
              )}
              <span className={`text-[9px] sm:text-[10px] font-black uppercase tracking-widest ${file.type === 'Notes' ? 'text-emerald-500' : 'text-teal-500'}`}>
                {file.type === 'Notes' ? 'Note' : 'Gaka'}
              </span>
            </div>
            <h4 className="font-black text-slate-800 dark:text-white/95 text-base sm:text-lg leading-tight group-hover:text-emerald-900 dark:group-hover:text-emerald-400 transition-colors truncate max-w-[200px] sm:max-w-md">
              {file.title}
            </h4>
          </div>
        </div>
        <div className="flex items-center justify-between sm:justify-end gap-3 sm:gap-4">
          <div className="flex items-center bg-slate-100/50 dark:bg-black/40 rounded-2xl p-1.5 border dark:border-white/10 shadow-sm">
            {profile?.role === 'admin' ? (
              <>
                <button onClick={() => openEditModal(file)} className="p-2 text-slate-500 dark:text-white/60 hover:text-emerald-600 dark:hover:text-emerald-400 active:scale-90"><EditIcon className="w-5 h-5" /></button>
                <div className="w-px h-5 bg-slate-200 dark:bg-white/10 mx-1"></div>
                <button onClick={() => handleDeleteResource(file.id)} className="p-2 text-slate-500 dark:text-white/60 hover:text-red-500 dark:hover:text-red-400 active:scale-90"><TrashIcon className="w-5 h-5" /></button>
              </>
            ) : (
              <>
                {profile && (
                  <button 
                    onClick={() => toggleSave(file.id)} 
                    className={`p-2 active:scale-90 ${isSaved ? 'text-emerald-600 dark:text-emerald-400' : 'text-slate-400 dark:text-white/30 hover:text-emerald-600 dark:hover:text-emerald-400'}`}
                  >
                    {isSaved ? <BookmarkFilledIcon className="w-5 h-5" /> : <BookmarkIcon className="w-5 h-5" />}
                  </button>
                )}
                {!profile && <button onClick={() => handleShare(file.title)} className="p-2 text-slate-400 dark:text-white/30 hover:text-emerald-600 active:scale-90"><ShareIcon className="w-5 h-5" /></button>}
                <div className="w-px h-5 bg-slate-200 dark:bg-white/10 mx-1"></div>
                <a href={file.viewUrl} target="_blank" rel="noopener noreferrer" className="p-2 text-slate-500 dark:text-white/60 hover:text-emerald-600 active:scale-90"><ViewIcon className="w-5 h-5" /></a>
              </>
            )}
          </div>
          <a 
            href={file.downloadUrl} 
            onClick={onDownload}
            className={`flex-1 sm:flex-none flex items-center justify-center space-x-2 px-6 py-3 sm:px-10 sm:py-4 font-black text-[10px] sm:text-[11px] uppercase tracking-widest rounded-xl sm:rounded-2xl shadow-xl active:scale-95 transition-all ${
              isDownloading ? 'bg-slate-800 dark:bg-black text-white' : 'bg-emerald-600 dark:bg-emerald-500 text-white hover:bg-emerald-700'
            }`}
          >
            {isDownloading ? <div className="w-3.5 h-3.5 border-2 border-white/20 border-t-white rounded-full animate-spin"></div> : <><DownloadIcon className="w-3.5 h-3.5 sm:w-4 sm:h-4" /><span>Download</span></>}
          </a>
        </div>
      </div>
    );
  };

  if (isLoading) return (
    <div className="min-h-screen flex items-center justify-center bg-white dark:bg-black">
      <div className="book-loader">
        <div className="book-back"></div>
        {[1, 2, 3].map(i => <div key={i} className="book-page"></div>)}
      </div>
    </div>
  );

  if (currentView === 'auth') return <AuthPage onLogin={handleLogin} onSignup={handleSignup} onBack={() => navigateTo('home')} isDark={isDark} />;

  return (
    <div className={`min-h-screen flex flex-col transition-colors duration-500 ${isDark ? 'dark bg-black text-white/90' : 'bg-[#fcfdfe] text-slate-900'}`}>
      <Navbar 
        onHomeClick={() => navigateTo('home')} 
        onExploreClick={() => navigateTo('modules')}
        onSavedClick={() => navigateTo('saved')}
        onAboutClick={() => navigateTo('about')}
        onLogoutClick={handleLogout}
        onAuthClick={(t) => navigateTo('auth')}
        isDark={isDark}
        onToggleDark={() => setIsDark(!isDark)}
        profile={profile}
        currentView={currentView}
      />

      <main className="flex-grow container mx-auto max-w-7xl px-4 py-8 sm:py-16 sm:px-10">
        {currentView === 'home' && (
          <div className="animate-fade-in flex flex-col items-center text-center pt-8 pb-16 sm:pt-16 sm:pb-32 lg:pt-32">
            <div className="inline-flex items-center space-x-3 bg-emerald-50 dark:bg-[#1E1E1E] px-5 py-2 rounded-full mb-8 border border-emerald-100/50 dark:border-white/5">
              <span className="w-2 h-2 rounded-full bg-emerald-500 animate-pulse"></span>
              <span className="text-[10px] font-black uppercase tracking-widest text-emerald-800 dark:text-emerald-400">MUST CS Portal</span>
            </div>
            <h2 className="text-4xl sm:text-6xl md:text-7xl lg:text-[100px] font-black mb-8 tracking-tighter leading-[1] max-w-5xl">
              Centralized <span className="gradient-text">Academic</span> <br className="hidden sm:block"/> Repository.
            </h2>
            <p className="text-base sm:text-xl md:text-2xl text-slate-500 dark:text-white/40 max-w-3xl mb-12 font-medium px-4">Verified materials for MUST Computer Science students.</p>
            <button onClick={() => navigateTo('modules')} className="group flex items-center px-10 py-5 sm:px-24 sm:py-7 bg-emerald-600 dark:bg-emerald-500 text-white rounded-full font-black text-sm sm:text-xl shadow-2xl hover:scale-105 transition-all">
              Explore Resources <ChevronRightIcon className="ml-3 sm:ml-4 w-5 h-5 sm:w-6 sm:h-6 group-hover:translate-x-2 transition-transform" />
