          </div>
        )}

        {currentView === 'modules' && (
          <div className="animate-fade-in">
            <div className="flex flex-col lg:flex-row lg:items-end justify-between mb-12 sm:mb-16 gap-8">
              <div className="space-y-3">
                <h2 className="text-4xl sm:text-7xl font-black tracking-tighter">Modules</h2>
                <p className="text-slate-500 dark:text-white/40 font-semibold text-base sm:text-lg">Browse curated MUST CS directory.</p>
              </div>
